/// abstract_state_progress_nonnegative: audit_nonce ≥ 0
fn abstract_state_progress_nonnegative(s: &State) -> bool {
    s.audit_nonce >= 0
}

/// protocol_fee_bps_bounded: protocol_fee_bps ≤ 9999
fn protocol_fee_bps_bounded(s: &State) -> bool {
    s.protocol_fee_bps <= 9999
}

/// claim_payment_bounded: paid_amount ≤ approved_amount
fn claim_payment_bounded(s: &State) -> bool {
    s.paid_amount <= s.approved_amount
}

/// fee_withdrawals_bounded: withdrawn_fees ≤ accrued_fees
fn fee_withdrawals_bounded(s: &State) -> bool {
    s.withdrawn_fees <= s.accrued_fees
}

/// allocation_cap_bounded: allocated_amount ≤ cap_amount
fn allocation_cap_bounded(s: &State) -> bool {
    s.allocated_amount <= s.cap_amount
}

fn initialize_protocol_governance(s: &mut State, args: InitializeProtocolGovernanceArgs) -> bool {
    if !(args.protocol_fee_bps <= 9999) {
        return false;
    }
    if s.status != Status::Uninitialized {
        return false;
    }
    s.protocol_fee_bps = args.protocol_fee_bps;
    s.emergency_pause = args.emergency_pause;
    s.audit_nonce = 0;
    s.status = Status::Live;
    true
}

