proptest! {
    #![proptest_config(ProptestConfig::with_cases(256))]
    #[test]
    fn state_machine_sequence(ops in proptest::collection::vec(arb_op(), 1..20)) {
        let mut s = State {
            audit_nonce: 0,
            protocol_fee_bps: 0,
            emergency_pause: 0,
            allowed_rail_mask: 0,
            pause_flags: 0,
            active: 0,
            total_assets: 0,
            last_price_usd_1e8: 0,
            last_price_confidence_bps: 0,
            last_price_published_at_ts: 0,
            accrued_fees: 0,
            withdrawn_fees: 0,
            membership_mode: 0,
            eligibility_status: 0,
            delegated_rights: 0,
            funded_amount: 0,
            spent_amount: 0,
            reserved_amount: 0,
            paid_amount: 0,
            approved_amount: 0,
            denied_amount: 0,
            pending_amount: 0,
            activated_amount: 0,
            treasury_locked_amount: 0,
            refunded_amount: 0,
            canceled_amount: 0,
            next_queue_index: 0,
            refunded_at: 0,
            intake_status: 0,
            review_state: 0,
            recovered_amount: 0,
            appeal_count: 0,
            attestation_count: 0,
            supported_schema_count: 0,
            updated_at_ts: 0,
            updated_at: 0,
            created_at_ts: 0,
            closed_at: 0,
            oracle_fee_bps: 0,
            quorum_m: 0,
            quorum_n: 0,
            challenge_window_secs: 0,
            cap_amount: 0,
            weight_bps: 0,
            allocated_amount: 0,
            allocated_assets: 0,
            total_allocated: 0,
            pending_redemption_shares: 0,
            pending_redemption_assets: 0,
            pending_redemptions: 0,
            total_shares: 0,
            nav_assets: 0,
            queue_only_redemptions: 0,
            credentialed: 0,
            claimed: 0,
            verified: 0,
            closed_outcome_schema_count: 0,
            commitment_deposit_amount: 0,
            refund_amount: 0,
            settlement_net_payout_amount: 0,
            claim_net_payout_amount: 0,
            redemption_net_payout_amount: 0,
            fee_withdrawal_amount: 0,
            bump: 0,
        };
        let mut lifecycle = Lifecycle::Uninitialized;
        let mut initialized = false;
        for (i, op) in ops.iter().enumerate() {
            let next_lifecycle = lifecycle_transition(lifecycle, op);
            if next_lifecycle.is_none() {
                continue; // skip ops not valid in current lifecycle state
            }
            if apply_op(&mut s, op) {
                if let Some(next) = next_lifecycle {
                    lifecycle = next;
                }
                if !initialized {
                    initialized = true;
                    continue; // skip property checks on init transition
                }
                // Check all properties after each successful transition
                prop_assert!(abstract_state_progress_nonnegative(&s),
                    "abstract_state_progress_nonnegative violated after op {:?} (step {})", op, i);
                prop_assert!(protocol_fee_bps_bounded(&s),
                    "protocol_fee_bps_bounded violated after op {:?} (step {})", op, i);
                prop_assert!(claim_payment_bounded(&s),
                    "claim_payment_bounded violated after op {:?} (step {})", op, i);
                prop_assert!(fee_withdrawals_bounded(&s),
                    "fee_withdrawals_bounded violated after op {:?} (step {})", op, i);
                prop_assert!(allocation_cap_bounded(&s),
                    "allocation_cap_bounded violated after op {:?} (step {})", op, i);
            }
        }
    }
}
